1	<!DOCTYPE html>
2	<html lang="en" data-theme="dark">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>VOID — Design Collective</title>
7	<style>
8	  @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700&family=Space+Mono:wght@400;700&display=swap');
9	
10	  :root {
11	    --black: #000;
12	    --white: #fff;
13	    --gray-100: #f5f5f5;
14	    --gray-200: #e0e0e0;
15	    --gray-300: #b0b0b0;
16	    --gray-400: #808080;
17	    --gray-500: #505050;
18	    --gray-600: #303030;
19	    --gray-700: #1a1a1a;
20	    --gray-800: #0a0a0a;
21	    --bg: var(--black);
22	    --fg: var(--white);
23	    --fg-dim: var(--gray-300);
24	    --fg-muted: var(--gray-400);
25	    --border: var(--gray-700);
26	    --border-subtle: var(--gray-800);
27	  }
28	
29	  [data-theme="light"] {
30	    --bg: var(--white);
31	    --fg: var(--black);
32	    --fg-dim: var(--gray-600);
33	    --fg-muted: var(--gray-500);
34	    --border: var(--gray-200);
35	    --border-subtle: var(--gray-100);
36	  }
37	
38	  * { margin: 0; padding: 0; box-sizing: border-box; border-radius: 0; }
39	
40	  html {
41	    scroll-behavior: smooth;
42	  }
43	
44	  body {
45	    background: var(--bg);
46	    color: var(--fg);
47	    font-family: 'Space Grotesk', sans-serif;
48	    overflow-x: hidden;
49	    -webkit-font-smoothing: antialiased;
50	    cursor: none;
51	    transition: background 0.6s ease, color 0.6s ease;
52	  }
53	
54	  /* ============================================
55	     CUSTOM CURSOR SYSTEM
56	   ============================================ */
57	  .cursor-main {
58	    position: fixed;
59	    width: 12px;
60	    height: 12px;
61	    background: var(--fg);
62	    pointer-events: none;
63	    z-index: 9999;
64	    mix-blend-mode: difference;
65	    transform: translate(-50%, -50%);
66	    transition: width 0.2s, height 0.2s, border-radius 0.1s;
67	  }
68	  .cursor-main.hovering {
69	    width: 32px;
70	    height: 32px;
71	  }
72	
73	  .cursor-follower {
74	    position: fixed;
75	    width: 40px;
76	    height: 40px;
77	    border: 1px solid var(--fg);
78	    pointer-events: none;
79	    z-index: 9998;
80	    mix-blend-mode: difference;
81	    transform: translate(-50%, -50%);
82	    opacity: 0.5;
83	  }
84	  .cursor-follower.hovering {
85	    width: 80px;
86	    height: 80px;
87	    opacity: 0.3;
88	  }
89	
90	  /* ============================================
91	     GRAIN OVERLAY
92	   ============================================ */
93	  .grain-overlay {
94	    position: fixed;
95	    inset: 0;
96	    pointer-events: none;
97	    z-index: 9990;
98	    opacity: 0.04;
99	    mixture: blend-mode: multiply;
100	  }
101	  .grain-overlay canvas {
102	    width: 100%;
103	    height: 100%;
104	  }
105	
106	  .scanlines {
107	    position: fixed;
108	    inset: 0;
109	    pointer-events: none;
110	    z-index: 9989;
111	    opacity: 0;
112	    background: repeating-linear-gradient(
113	      0deg,
114	      transparent 0px,
115	      transparent 2px,
116	      rgba(0,0,0,0.03) 2px,
117	      rgba(0,0,0,0.03) 4px
118	    );
119	    transition: opacity 0.6s;
120	  }
121	  .scanlines.visible {
122	    opacity: 1;
123	  }
124	
125	  /* ============================================
126	     PAGE TRANSITION
127	   ============================================ */
128	  .page-transition {
129	    position: fixed;
130	    inset: 0;
131	    background: var(--fg);
132	    z-index: 10000;
133	    transform: translateY(100%);
134	    pointer-events: none;
135	  }
136	  .page-transition.wiping {
137	    animation: pageWipe 0.8s ease-in-out;
138	  }
139	  @keyframes pageWipe {
140	    0% { transform: translateY(100%); }
141	    40% { transform: translateY(0%); }
142	    60% { transform: translateY(0%); }
143	    100% { transform: translateY(-100%); }
144	  }
145	
146	  /* ============================================
147	     NAVIGATION
148	   ============================================ */
149	  nav {
150	    position: fixed;
151	    top: 0;
152	    left: 0;
153	    right: 0;
154	    display: flex;
155	    justify-content: space-between;
156	    align-items: center;
157	    padding: 20px 40px;
158	    z-index: 200;
159	    border-bottom: 1px solid var(--border);
160	    background: var(--bg);
161	    transition: all 0.4s ease;
162	    cursor: none;
163	  }
164	
165	  .logo {
166	    font-family: 'Space Mono', monospace;
167	    font-size: 18px;
168	    font-weight: 700;
169	    letter-spacing: 8px;
170	    text-transform: uppercase;
171	    color: var(--fg);
172	  }
173	
174	  .nav-right {
175	    display: flex;
176	    align-items: center;
177	    gap: 32px;
178	  }
179	
180	  .nav-links {
181	    display: flex;
182	    gap: 32px;
183	    list-style: none;
184	  }
185	
186	  .nav-links a {
187	    color: var(--fg-muted);
188	    text-decoration: none;
189	    font-size: 12px;
190	    letter-spacing: 3px;
191	    text-transform: uppercase;
192	    transition: color 0.2s;
193	    position: relative;
194	  }
195	  .nav-links a::after {
196	    content: '';
197	    position: absolute;
198	    bottom: -4px;
199	    left: 0;
200	    width: 0;
201	    height: 1px;
202	    background: var(--fg);
203	    transition: width 0.3s ease;
204	  }
205	  .nav-links a:hover { color: var(--fg); }
206	  .nav-links a:hover::after { width: 100%; }
207	
208	  .theme-toggle {
209	    background: none;
210	    border: 1px solid var(--border);
211	    color: var(--fg);
212	    padding: 8px 16px;
213	    font-family: 'Space Mono', monospace;
214	    font-size: 11px;
215	    letter-spacing: 3px;
216	    text-transform: uppercase;
217	    cursor: pointer;
218	    transition: all 0.2s;
219	    text-transform: uppercase;
220	  }
221	  .theme-toggle:hover {
222	    background: var(--fg);
223	    color: var(--bg);
224	  }
225	
226	  /* ============================================
227	     SCROLL ANIMATIONS
228	   ============================================ */
229	  .reveal {
230	    opacity: 0;
231	    transform: translateY(40px);
232	    transition: opacity 0.8s ease, transform 0.8s ease;
233	  }
234	  .reveal.revealed {
235	    opacity: 1;
236	    transform: translateY(0);
237	  }
238	  .reveal-delay-1 { transition-delay: 0.1s; }
239	  .reveal-delay-2 { transition-delay: 0.2s; }
240	  .reveal-delay-3 { transition-delay: 0.3s; }
241	  .reveal-delay-4 { transition-delay: 0.4s; }
242	
243	  .reveal-left {
244	    opacity: 0;
245	    transform: translateX(-60px);
246	    transition: opacity 0.8s ease, transform 0.8s ease;
247	  }
248	  .reveal-left.revealed {
249	    opacity: 1;
250	    transform: translateX(0);
251	  }
252	
253	  .reveal-right {
254	    opacity: 0;
255	    transform: translateX(60px);
256	    transition: opacity 0.8s ease, transform 0.8s ease;
257	  }
258	  .reveal-right.revealed {
259	    opacity: 1;
260	    transform: translateX(0);
261	  }
262	
263	  .reveal-scale {
264	    opacity: 0;
265	    transform: scale(0.9);
266	    transition: opacity 0.8s ease, transform 0.8s ease;
267	  }
268	  .reveal-scale.revealed {
269	    opacity: 1;
270	    transform: scale(1);
271	  }
272	
273	  /* ============================================
274	     HERO SECTION
275	   ============================================ */
276	  .hero {
277	    min-height: 100vh;
278	    display: flex;
279	    flex-direction: column;
280	    justify-content: center;
281	    padding: 120px 80px;
282	    position: relative;
283	    border-bottom: 1px solid var(--border);
284	    overflow: hidden;
285	  }
286	
287	  .hero-tag {
288	    font-family: 'Space Mono', monospace;
289	    font-size: 11px;
290	    letter-spacing: 6px;
291	    text-transform: uppercase;
292	    color: var(--fg-muted);
293	    margin-bottom: 32px;
294	    display: flex;
295	    align-items: center;
296	    gap: 16px;
297	  }
298	  .hero-tag::before {
299	    content: '';
300	    width: 40px;
301	    height: 1px;
302	    background: var(--fg-muted);
303	  }
304	
305	  .hero-title-wrap {
306	    position: relative;
307	    mix-blend-mode: difference;
308	  }
309	
310	  .hero-title {
311	    font-size: clamp(60px, 10vw, 140px);
312	    font-weight: 700;
313	    line-height: 0.9;
314	    letter-spacing: -4px;
315	    text-transform: uppercase;
316	    max-width: 900px;
317	    color: var(--fg);
318	  }
319	  .hero-title .outline {
320	    color: var(--bg);
321	    -webkit-text-stroke: 2px var(--fg);
322	    text-stroke: 2px var(--fg);
323	  }
324	
325	  .kinetic-letter {
326	    display: inline-block;
327	    transition: transform 0.15s ease;
328	    will-change: transform;
329	  }
330	
331	  .hero-desc {
332	    max-width: 420px;
333	    margin-top: 48px;
334	    font-size: 16px;
335	    line-height: 1.6;
336	    color: var(--fg-dim);
337	    font-weight: 300;
338	  }
339	
340	  .hero-cta {
341	    margin-top: 56px;
342	    display: inline-block;
343	    padding: 16px 48px;
344	    background: var(--fg);
345	    color: var(--bg);
346	    text-decoration: none;
347	    font-family: 'Space Mono', monospace;
348	    font-size: 12px;
349	    letter-spacing: 4px;
350	    text-transform: uppercase;
351	    font-weight: 700;
352	    transition: all 0.2s;
353	    border: 2px solid var(--fg);
354	  }
355	  .hero-cta:hover {
356	    background: var(--bg);
357	    color: var(--fg);
358	  }
359	
360	  /* DECORATIVE GRID */
361	  .grid-overlay {
362	    position: absolute;
363	    right: 80px;
364	    bottom: 80px;
365	    display: grid;
366	    grid-template-columns: repeat(4, 60px);
367	    grid-template-rows: repeat(4, 60px);
368	    gap: 1px;
369	  }
370	  .grid-cell {
371	    border: 1px solid var(--border);
372	    background: var(--bg);
373	    transition: background 0.3s, border-color 0.3s;
374	  }
375	  .grid-cell.active {
376	    background: var(--fg);
377	  }
378	  .grid-cell:hover {
379	    border-color: var(--fg);
380	  }
381	
382	  /* ============================================
383	     VERTICAL TEXT ELEMENT
384	   ============================================ */
385	  .vertical-text {
386	    position: absolute;
387	    font-family: 'Space Mono', monospace;
388	    font-size: 10px;
389	    letter-spacing: 6px;
390	    text-transform: uppercase;
391	    color: var(--fg-muted);
392	    opacity: 0.5;
393	  }
394	  .vertical-text.left {
395	    left: 20px;
396	    top: 50%;
397	    transform: rotate(-90deg);
398	    transform-origin: 0 0;
399	  }
400	  .vertical-text.right {
401	    right: 20px;
402	    top: 50%;
403	    transform: rotate(90deg);
404	    transform-origin: 0 0;
405	  }
406	
407	  /* ============================================
408	     STATEMENT SECTION
409	   ============================================ */
410	  .statement {
411	    padding: 160px 80px;
412	    text-align: center;
413	    position: relative;
414	    background: var(--fg);
415	    color: var(--bg);
416	  }
417	
418	  .statement-text {
419	    font-size: clamp(32px, 6vw, 80px);
420	    font-weight: 700;
421	    text-transform: uppercase;
422	    line-height: 1.05;
423	    letter-spacing: -3px;
424	    max-width: 1000px;
425	    margin: 0 auto;
426	    mix-blend-mode: difference;
427	    color: inherit;
428	  }
429	
430	  .statement-author {
431	    font-family: 'Space Mono', monospace;
432	    font-size: 11px;
433	    letter-spacing: 6px;
434	    text-transform: uppercase;
435	    color: var(--fg-muted);
436	    margin-top: 64px;
437	  }
438	
439	  .quote-marks {
440	    font-size: 120px;
441	    font-family: 'Space Mono', monospace;
442	    position: absolute;
443	    top: 20px;
444	    left: 80px;
445	    color: var(--fg);
446	    opacity: 0.1;
447	    line-height: 1;
448	  }
449	
450	  /* ============================================
451	     MARQUEE
452	   ============================================ */
453	  .marquee-section {
454	    padding: 40px 0;
455	    border-bottom: 1px solid var(--border);
456	    overflow: hidden;
457	  }
458	
459	  .marquee {
460	    display: flex;
461	    gap: 48px;
462	    animation: marquee 20s linear infinite;
463	  }
464	
465	  @keyframes marquee {
466	    from { transform: translateX(0); }
467	    to { transform: translateX(-50%); }
468	  }
469	
470	  .marquee-item {
471	    font-size: 72px;
472	    font-weight: 700;
473	    text-transform: uppercase;
474	    white-space: nowrap;
475	    letter-spacing: -2px;
476	    color: var(--border);
477	  }
478	  .marquee-item .dot {
479	    display: inline-block;
480	    width: 12px;
481	    height: 12px;
482	    background: var(--fg);
483	    margin: 0 32px;
484	    vertical-align: middle;
485	  }
486	
487	  /* ============================================
488	     STATS
489	   ============================================ */
490	  .stats {
491	    display: grid;
492	    grid-template-columns: repeat(4, 1fr);
493	    background: var(--bg);
494	  }
495	
496	  .stat {
497	    padding: 64px 48px;
498	    border-right: 1px solid var(--border);
499	    text-align: center;
500	    transition: background 0.3s;
501	  }
502	  .stat:last-child { border-right: none; }
503	  .stat:hover { background: var(--gray-700); }
504	  [data-theme="light"] .stat:hover { background: var(--gray-100); }
505	
506	  .stat-value {
507	    font-family: 'Space Mono', monospace;
508	    font-size: 56px;
509	    font-weight: 700;
510	    letter-spacing: -2px;
511	    margin-bottom: 12px;
512	  }
513	
514	  .stat-label {
515	    font-size: 11px;
516	    letter-spacing: 4px;
517	    text-transform: uppercase;
518	    color: var(--fg-muted);
519	  }
520	
521	  /* ============================================
522	     SECTION COMMON
523	   ============================================ */
524	  .section {
525	    padding: 80px;
526	    border-bottom: 1px solid var(--border);
527	  }
528	
529	  .section-header {
530	    margin-bottom: 64px;
531	    display: flex;
532	    justify-content: space-between;
533	    align-items: flex-start;
534	  }
535	
536	  .section-label {
537	    font-family: 'Space Mono', monospace;
538	    font-size: 11px;
539	    letter-spacing: 6px;
540	    text-transform: uppercase;
541	    color: var(--fg-muted);
542	    margin-bottom: 16px;
543	  }
544	
545	  .section-title {
546	    font-size: clamp(36px, 5vw, 64px);
547	    font-weight: 700;
548	    text-transform: uppercase;
549	    letter-spacing: -2px;
550	  }
551	
552	  .section-count {
553	    font-family: 'Space Mono', monospace;
554	    font-size: 11px;
555	    color: var(--fg-muted);
556	    letter-spacing: 2px;
557	  }
558	
559	  /* ============================================
560	     FEATURES
561	   ============================================ */
562	  .features {
563	    display: grid;
564	    grid-template-columns: repeat(3, 1fr);
565	    gap: 1px;
566	    background: var(--border);
567	  }
568	
569	  .feature {
570	    padding: 48px;
571	    background: var(--bg);
572	    transition: background 0.3s, color 0.3s;
573	    position: relative;
574	    overflow: hidden;
575	    cursor: pointer;
576	  }
577	  .feature::before {
578	    content: '';
579	    position: absolute;
580	    inset: 0;
581	    background: var(--fg);
582	    transform: translateY(100%);
583	    transition: transform 0.4s ease;
584	    z-index: 0;
585	  }
586	  .feature:hover::before {
587	    transform: translateY(0%);
588	  }
589	  .feature:hover {
590	    color: var(--bg);
591	  }
592	  .feature > * {
593	    position: relative;
594	    z-index: 1;
595	  }
596	
597	  .feature-number {
598	    font-family: 'Space Mono', monospace;
599	    font-size: 72px;
600	    font-weight: 700;
601	    color: var(--border);
602	    line-height: 1;
603	    margin-bottom: 32px;
604	    transition: color 0.3s;
605	  }
606	  .feature:hover .feature-number {
607	    color: var(--fg);
608	  }
609	
610	  .feature-title {
611	    font-size: 20px;
612	    font-weight: 600;
613	    text-transform: uppercase;
614	    letter-spacing: 2px;
615	    margin-bottom: 16px;
616	  }
617	
618	  .feature-desc {
619	    font-size: 14px;
620	    line-height: 1.7;
621	    color: var(--fg-dim);
622	    font-weight: 300;
623	    transition: color 0.3s;
624	  }
625	  .feature:hover .feature-desc {
626	    color: var(--fg);
627	  }
628	
629	  /* ============================================
630	     WORK/PROJECTS SECTION
631	   ============================================ */
632	  .work-grid {
633	    display: grid;
634	    grid-template-columns: 1fr 1fr;
635	    gap: 1px;
636	    background: var(--border);
637	  }
638	
639	  .work-item {
640	    aspect-ratio: 4/3;
641	    background: var(--bg);
642	    position: relative;
643	    display: flex;
644	    flex-direction: column;
645	    justify-content: flex-end;
646	    padding: 32px;
647	    overflow: hidden;
648	    cursor: pointer;
649	    transition: background 0.3s;
650	  }
651	  .work-item:hover { background: var(--gray-600); }
652	
653	  .work-preview {
654	    position: absolute;
655	    inset: 32px;
656	    bottom: 100px;
657	    overflow: hidden;
658	    opacity: 0;
659	    transition: opacity 0.4s ease;
660	  }
661	  .work-item:hover .work-preview { opacity: 1; }
662	
663	  .work-preview-inner {
664	    width: 100%;
665	    height: 100%;
666	    background: var(--gray-600);
667	    overflow: hidden;
668	  }
669	  [data-theme="light"] .work-preview-inner { background: var(--gray-100); }
670	
671	  .work-preview-grid {
672	    width: 100%;
673	    height: 100%;
674	    background-size: 20px 20px;
675	    background-image:
676	      linear-gradient(to right, var(--bg) 1px, transparent 1px),
677	      linear-gradient(to bottom, var(--bg) 1px, transparent 1px);
678	    opacity: 0.2;
679	  }
680	
681	  .work-year {
682	    font-family: 'Space Mono', monospace;
683	    font-size: 10px;
684	    color: var(--fg-muted);
685	    margin-bottom: 8px;
686	  }
687	
688	  .work-title {
689	    font-size: 28px;
690	    font-weight: 700;
691	    text-transform: uppercase;
692	    letter-spacing: -1px;
693	  }
694	
695	  .work-tag {
696	    font-family: 'Space Mono', monospace;
697	    font-size: 10px;
698	    color: var(--fg-muted);
699	    margin-top: 8px;
700	    letter-spacing: 3px;
701	    text-transform: uppercase;
702	  }
703	
704	  .work-num {
705	    position: absolute;
706	    top: 32px;
707	    right: 32px;
708	    font-family: 'Space Mono', monospace;
709	    font-size: 64px;
710	    font-weight: 700;
711	    color: var(--border);
712	    transition: color 0.3s;
713	  }
714	  .work-item:hover .work-num { color: var(--fg); }
715	
716	  /* ============================================
717	     GALLERY
718	   ============================================ */
719	  .gallery {
720	    display: grid;
721	    grid-template-columns: 1fr 1fr;
722	    gap: 1px;
723	    background: var(--border);
724	  }
725	
726	  .gallery-item {
727	    aspect-ratio: 1;
728	    background: var(--bg);
729	    position: relative;
730	    overflow: hidden;
731	    display: flex;
732	    align-items: center;
733	    justify-content: center;
734	    transition: background 0.3s;
735	    cursor: pointer;
736	  }
737	  .gallery-item:hover { background: var(--gray-600); }
738	
739	  .gallery-pattern {
740	    position: absolute;
741	    inset: 0;
742	    transition: opacity 0.3s;
743	  }
744	  .gallery-item:hover .gallery-pattern { opacity: 0.3; }
745	
746	  .gallery-item:nth-child(1) .gallery-pattern {
747	    background: repeating-linear-gradient(0deg, var(--fg) 0px, var(--fg) 2px, transparent 2px, transparent 12px);
748	    opacity: 0.15;
749	  }
750	  .gallery-item:nth-child(2) .gallery-pattern {
751	    background: repeating-linear-gradient(45deg, var(--fg) 0px, var(--fg) 1px, transparent 1px, transparent 8px);
